async function main() {
  let ok=0
  for(let i=0;i<ALL.length;i+=5) {
    const batch=ALL.slice(i,i+5)
    const success=await insert(batch)
    if(success) ok+=batch.length
    console.log(`Batch ${Math.floor(i/5)+1}: ${success?'OK':'FAIL'}`)
  }
  console.log(`Done: ${ok}/${ALL.length}`)
}
main()
